import type {
  SwapQuote, SwapTransaction, ExecuteResult, TokenRecord, PriceSnapshot,
  TransferBuildResponse, PositionsResponse, OpenOrder, DcaOrder, PendingAction, ProviderInfo,
} from '../types';

export class TradeApiClient {
  constructor(
    private baseUrl: string,
    private tokenFn?: () => string | null,
    private apiKey?: string,
  ) {}

  private async request<T>(path: string, options?: RequestInit): Promise<T> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      ...(options?.headers as Record<string, string>),
    };
    const token = this.tokenFn?.();
    if (token) headers['Authorization'] = `Bearer ${token}`;
    if (this.apiKey) headers['x-api-key'] = this.apiKey;

    const resp = await fetch(`${this.baseUrl}${path}`, { ...options, headers });
    if (!resp.ok) {
      const body = await resp.json().catch(() => ({ error: { message: resp.statusText } }));
      throw new TradeApiError(resp.status, body?.error?.code ?? 'UNKNOWN', body?.error?.message ?? resp.statusText);
    }
    return resp.json();
  }

  private get<T>(path: string) { return this.request<T>(path); }
  private post<T>(path: string, body: unknown) {
    return this.request<T>(path, { method: 'POST', body: JSON.stringify(body) });
  }
  private del<T>(path: string, body?: unknown) {
    return this.request<T>(path, { method: 'DELETE', body: body ? JSON.stringify(body) : undefined });
  }

  // --- Tokens ---
  getTokens(category?: string) {
    const q = category ? `?category=${category}` : '';
    return this.get<{ tokens: TokenRecord[]; count: number }>(`/tokens${q}`);
  }
  getToken(mint: string) { return this.get<TokenRecord>(`/tokens/${mint}`); }

  // --- Swap ---
  getQuote(params: { inputMint: string; outputMint: string; amount: string; slippageBps?: number; provider?: string }) {
    return this.post<SwapQuote>('/swap/quote', params);
  }
  buildSwap(quote: SwapQuote, userPublicKey: string) {
    return this.post<SwapTransaction>('/swap/build', { quote, userPublicKey });
  }
  compareQuotes(inputMint: string, outputMint: string, amount: string) {
    return this.get<SwapQuote[]>(`/swap/compare?inputMint=${inputMint}&outputMint=${outputMint}&amount=${amount}`);
  }
  executeSwap(signedTransaction: string, provider: string, requestId?: string) {
    return this.post<ExecuteResult>('/swap/execute', { signedTransaction, provider, requestId });
  }
  getProviders() { return this.get<ProviderInfo[]>('/swap/providers'); }

  // --- Prices ---
  getPrice(mint: string) { return this.get<PriceSnapshot>(`/prices/${mint}`); }
  getBatchPrices(mints: string[]) { return this.post<{ prices: PriceSnapshot[] }>('/prices/batch', { mints }); }

  // --- Transfers ---
  buildTransfer(params: { sender: string; recipient: string; mint: string; amount: string; memo?: string }) {
    return this.post<TransferBuildResponse>('/transfers/build', params);
  }
  executeTransfer(signedTransaction: string) {
    return this.post<ExecuteResult>('/transfers/execute', { signedTransaction, provider: 'rpc' });
  }
  resolveAddress(address: string) {
    return this.get<{ input: string; resolved: string; type: string }>(`/transfers/resolve/${address}`);
  }

  // --- Orders ---
  createLimitOrder(params: { maker: string; inputMint: string; outputMint: string; inAmount: string; outAmount: string; expiry?: string }) {
    return this.post<{ transaction: string; orderId: string }>('/orders/limit', params);
  }
  createStopLoss(params: { maker: string; inputMint: string; outputMint: string; inAmount: string; triggerPrice: string; slippageBps?: number }) {
    return this.post<{ transaction: string; orderId: string }>('/orders/stop-loss', params);
  }
  createTakeProfit(params: { maker: string; inputMint: string; outputMint: string; inAmount: string; triggerPrice: string; slippageBps?: number }) {
    return this.post<{ transaction: string; orderId: string }>('/orders/take-profit', params);
  }
  createDca(params: { maker: string; inputMint: string; outputMint: string; totalInAmount: string; perCycleAmount: string; cycleInterval: number }) {
    return this.post<{ transaction: string; orderId: string }>('/orders/dca', params);
  }
  cancelOrder(orderId: string, maker: string) {
    return this.del<{ transaction: string }>(`/orders/${orderId}`, { maker });
  }
  // --- Server-monitored orders ---
  createTrailingStop(params: { maker: string; walletId?: string; inputMint: string; outputMint: string; inAmount: string; trailPercent: number; slippageBps?: number }) {
    return this.post<{ orderId: string; currentPrice: string; initialTrigger: string; status: string }>('/orders/trailing-stop', params);
  }
  createOco(params: { maker: string; walletId?: string; inputMint: string; outputMint: string; inAmount: string; stopLoss: { triggerPrice: string; slippageBps: number }; takeProfit: { triggerPrice: string; slippageBps: number } }) {
    return this.post<{ ocoId: string; stopLossOrderId: string; takeProfitOrderId: string; status: string; linked: boolean; reason?: string }>('/orders/oco', params);
  }
  createBracket(params: { maker: string; walletId?: string; inputMint: string; outputMint: string; inAmount: string; stopLossPercent: number; takeProfitPercent: number; trailingStop?: boolean }) {
    return this.post<{ bracketId: string; entryTransaction: string; status: string }>('/orders/bracket', params);
  }

  getOpenOrders(wallet: string) {
    return this.get<{ limitOrders: OpenOrder[]; dcaOrders: DcaOrder[] }>(`/orders/wallet/${wallet}`);
  }

  // --- Positions ---
  getPositions(wallet: string) { return this.get<PositionsResponse>(`/positions/${wallet}`); }

  // --- Action Queue ---
  getPendingActions(wallet: string) { return this.get<PendingAction[]>(`/orders/actions/${wallet}`); }
  completeAction(actionId: string, signedTransaction: string) {
    return this.post<{ actionId: string; status: string; signature: string }>(
      `/orders/actions/${actionId}/complete`, { signedTransaction },
    );
  }
  dismissAction(actionId: string) {
    return this.post<{ actionId: string; status: string }>(`/orders/actions/${actionId}/dismiss`, {});
  }

  // --- Health ---
  getHealth() { return this.get<{ status: string; version: string }>('/health'); }
}

export class TradeApiError extends Error {
  constructor(public status: number, public code: string, message: string) {
    super(message);
    this.name = 'TradeApiError';
  }
}
